{
  "name": "Medivise AI",
  "description": "A stateless, privacy-first AI medical analysis application that stores all reports locally on your device. Analyze X-rays, MRIs, and medical documents using Gemini 3 Flash.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  username: string;
  passwordHash: string;
}

export interface MedicalReport {
  id: string;
  userId: string;
  timestamp: number;
  fileName: string;
  fileType: string;
  analysis: AnalysisResult;
}

export interface AnalysisResult {
  summary: string;
  faults: string[];
  goods: string[];
  temporary_guidance: string[];
  confidence: 'low' | 'medium' | 'high';
  disclaimer: string;
}

export enum Page {
  LOGIN = 'LOGIN',
  DASHBOARD = 'DASHBOARD',
  UPLOAD = 'UPLOAD',
  REPORTS = 'REPORTS',
  RESULT = 'RESULT'
}

import { User, MedicalReport } from './types';

const DB_NAME = 'MediviseDB';
const STORE_NAME = 'reports';
const DB_VERSION = 1;

/**
 * Simple SHA-256 implementation for local hashing
 */
export async function hashPassword(password: string): Promise<string> {
  const msgUint8 = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgUint8);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

/**
 * IndexedDB Wrapper
 */
class LocalDB {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);
      request.onerror = () => reject(request.error);
      request.onsuccess = () => {
        this.db = request.result;
        resolve();
      };
      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME, { keyPath: 'id' });
        }
      };
    });
  }

  async saveReport(report: MedicalReport): Promise<void> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const transaction = this.db!.transaction([STORE_NAME], 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(report);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async getReports(userId: string): Promise<MedicalReport[]> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const transaction = this.db!.transaction([STORE_NAME], 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => {
        const all = request.result as MedicalReport[];
        resolve(all.filter(r => r.userId === userId).sort((a, b) => b.timestamp - a.timestamp));
      };
      request.onerror = () => reject(request.error);
    });
  }

  async deleteReport(id: string): Promise<void> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const transaction = this.db!.transaction([STORE_NAME], 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
}

export const db = new LocalDB();

export const authStorage = {
  saveUser: (user: User) => {
    const users = authStorage.getUsers();
    users.push(user);
    localStorage.setItem('medivise_users', JSON.stringify(users));
  },
  getUsers: (): User[] => {
    const data = localStorage.getItem('medivise_users');
    return data ? JSON.parse(data) : [];
  },
  setSession: (username: string | null) => {
    if (username) localStorage.setItem('medivise_session', username);
    else localStorage.removeItem('medivise_session');
  },
  getSession: () => localStorage.getItem('medivise_session')
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "./types";

const SYSTEM_PROMPT = `You are a medical analysis AI. 
Analyze the provided medical data (images or documents) and return a structured report. 
Focus on identifying visible anomalies, positive findings, and providing temporary guidance.
STRICTLY ADHERE TO THE JSON FORMAT.
DISCLAIMER: This is not a medical diagnosis. Users must consult a healthcare professional.`;

export async function analyzeMedicalFile(
  file: File,
  base64Data: string
): Promise<AnalysisResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isImage = file.type.startsWith('image/') || file.name.toLowerCase().endsWith('.dicom');

  const contents = {
    parts: [
      {
        inlineData: {
          mimeType: isImage ? 'image/png' : 'application/pdf',
          data: base64Data
        }
      },
      {
        text: "Analyze this medical document or image. Provide a summary, faults found, good signs, and temporary guidance."
      }
    ]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          faults: { type: Type.ARRAY, items: { type: Type.STRING } },
          goods: { type: Type.ARRAY, items: { type: Type.STRING } },
          temporary_guidance: { type: Type.ARRAY, items: { type: Type.STRING } },
          confidence: { type: Type.STRING, description: "low, medium, or high" },
          disclaimer: { type: Type.STRING }
        },
        required: ["summary", "faults", "goods", "temporary_guidance", "confidence", "disclaimer"]
      }
    }
  });

  const text = response.text || "{}";
  try {
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Analysis failed. Please try again.");
  }
}

import React, { useState, useEffect } from 'react';
import { Page, User, MedicalReport, AnalysisResult } from './types';
import { authStorage, db, hashPassword } from './storage';
import { analyzeMedicalFile } from './geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowUpTrayIcon, 
  ClockIcon, 
  ArrowLeftOnRectangleIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  XCircleIcon,
  TrashIcon,
  ChevronLeftIcon,
  InformationCircleIcon
} from '@heroicons/react/24/outline';

export default function App() {
  const [currentPage, setCurrentPage] = useState<Page>(Page.LOGIN);
  const [currentUser, setCurrentUser] = useState<string | null>(authStorage.getSession());
  const [reports, setReports] = useState<MedicalReport[]>([]);
  const [activeReport, setActiveReport] = useState<MedicalReport | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth Handling
  const handleLogin = async (username: string, pass: string) => {
    const users = authStorage.getUsers();
    const hash = await hashPassword(pass);
    const existing = users.find(u => u.username === username);

    if (existing) {
      if (existing.passwordHash === hash) {
        completeLogin(username);
      } else {
        setError('Invalid credentials');
      }
    } else {
      // Auto-register for this demo
      const newUser = { username, passwordHash: hash };
      authStorage.saveUser(newUser);
      completeLogin(username);
    }
  };

  const completeLogin = (username: string) => {
    setCurrentUser(username);
    authStorage.setSession(username);
    setError(null);
    setCurrentPage(Page.DASHBOARD);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    authStorage.setSession(null);
    setCurrentPage(Page.LOGIN);
  };

  // Data Loading
  useEffect(() => {
    if (currentUser) {
      db.getReports(currentUser).then(setReports);
    }
  }, [currentUser, currentPage]);

  const onFileUpload = async (file: File) => {
    if (!currentUser) return;
    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const res = reader.result as string;
          resolve(res.split(',')[1]);
        };
        reader.readAsDataURL(file);
      });

      const base64 = await base64Promise;
      const result = await analyzeMedicalFile(file, base64);

      const newReport: MedicalReport = {
        id: Math.random().toString(36).substr(2, 9),
        userId: currentUser,
        timestamp: Date.now(),
        fileName: file.name,
        fileType: file.type,
        analysis: result
      };

      await db.saveReport(newReport);
      setActiveReport(newReport);
      setCurrentPage(Page.RESULT);
    } catch (err: any) {
      setError(err.message || "Failed to analyze file");
    } finally {
      setIsLoading(false);
    }
  };

  const deleteReport = async (id: string) => {
    await db.deleteReport(id);
    const updated = reports.filter(r => r.id !== id);
    setReports(updated);
  };

  // Rendering logic
  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} error={error} setError={setError} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setCurrentPage(Page.DASHBOARD)}>
              <ClipboardDocumentCheckIcon className="h-8 w-8 text-blue-600" />
              <span className="text-xl font-bold text-slate-900 tracking-tight">Medivise <span className="text-blue-600">AI</span></span>
            </div>
            <div className="flex items-center space-x-4">
              <span className="hidden sm:block text-sm text-slate-500 font-medium">Hello, {currentUser}</span>
              <button 
                onClick={handleLogout}
                className="p-2 text-slate-400 hover:text-red-600 transition-colors"
                title="Logout"
              >
                <ArrowLeftOnRectangleIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow max-w-5xl w-full mx-auto p-4 sm:p-6 lg:p-8">
        {currentPage === Page.DASHBOARD && (
          <DashboardView 
            onUpload={() => setCurrentPage(Page.UPLOAD)} 
            onViewHistory={() => setCurrentPage(Page.REPORTS)}
            latestReports={reports.slice(0, 3)}
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
          />
        )}
        {currentPage === Page.UPLOAD && (
          <UploadView 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onFileSelect={onFileUpload} 
            isLoading={isLoading} 
            error={error}
          />
        )}
        {currentPage === Page.REPORTS && (
          <ReportsListView 
            reports={reports} 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
            onDelete={deleteReport}
          />
        )}
        {currentPage === Page.RESULT && activeReport && (
          <ResultView 
            report={activeReport} 
            onBack={() => setCurrentPage(Page.REPORTS)} 
          />
        )}
      </main>

      {/* Persistent Disclaimer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-4 px-6 text-center text-xs text-slate-500">
        <p className="max-w-3xl mx-auto">
          <strong>MEDICAL DISCLAIMER:</strong> This tool is for educational purposes only. It uses AI to identify patterns and does not provide professional medical advice, diagnosis, or treatment. Always seek the advice of your physician or other qualified health provider with any questions you may have regarding a medical condition.
        </p>
      </footer>
    </div>
  );
}

// Sub-components (Helpers)

const LoginPage: React.FC<{ onLogin: (u: string, p: string) => void; error: string | null; setError: (s: string | null) => void }> = ({ onLogin, error, setError }) => {
  const [user, setUser] = useState('');
  const [pass, setPass] = useState('');

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 to-indigo-800 flex items-center justify-center p-4">
      <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center p-3 bg-blue-100 rounded-xl mb-4">
            <ClipboardDocumentCheckIcon className="h-10 w-10 text-blue-600" />
          </div>
          <h1 className="text-3xl font-bold text-slate-900">Medivise AI</h1>
          <p className="text-slate-500 mt-2">Private Medical Analysis Platform</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 text-sm rounded-lg flex items-start space-x-2">
            <XCircleIcon className="h-5 w-5 mt-0.5 shrink-0" />
            <span>{error}</span>
          </div>
        )}

        <form onSubmit={(e) => { e.preventDefault(); onLogin(user, pass); }}>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Username</label>
              <input 
                type="text" required value={user} onChange={(e) => setUser(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Enter username"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Password</label>
              <input 
                type="password" required value={pass} onChange={(e) => setPass(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Enter password"
              />
            </div>
            <button 
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-6 rounded-xl transition-all shadow-lg shadow-blue-200 transform hover:-translate-y-0.5"
            >
              Sign In / Register
            </button>
          </div>
        </form>

        <div className="mt-8 pt-6 border-t border-slate-100 flex items-center justify-center text-xs text-slate-400 space-x-1">
          <InformationCircleIcon className="h-4 w-4" />
          <span>All data stays on your device.</span>
        </div>
      </div>
    </div>
  );
};

const DashboardView: React.FC<{ onUpload: () => void; onViewHistory: () => void; latestReports: MedicalReport[]; onViewReport: (r: MedicalReport) => void }> = ({ onUpload, onViewHistory, latestReports, onViewReport }) => {
  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <button 
          onClick={onUpload}
          className="group relative overflow-hidden bg-white p-8 rounded-2xl shadow-sm border border-slate-200 hover:border-blue-400 hover:shadow-md transition-all text-left"
        >
          <div className="relative z-10">
            <div className="bg-blue-50 group-hover:bg-blue-600 transition-colors p-4 rounded-xl inline-block mb-4">
              <ArrowUpTrayIcon className="h-8 w-8 text-blue-600 group-hover:text-white transition-colors" />
            </div>
            <h2 className="text-2xl font-bold text-slate-900 mb-2">New Analysis</h2>
            <p className="text-slate-500">Upload X-rays, MRIs, or medical docs for instant AI summary.</p>
          </div>
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <ArrowUpTrayIcon className="h-32 w-32" />
          </div>
        </button>

        <button 
          onClick={onViewHistory}
          className="group relative overflow-hidden bg-white p-8 rounded-2xl shadow-sm border border-slate-200 hover:border-indigo-400 hover:shadow-md transition-all text-left"
        >
          <div className="relative z-10">
            <div className="bg-indigo-50 group-hover:bg-indigo-600 transition-colors p-4 rounded-xl inline-block mb-4">
              <ClockIcon className="h-8 w-8 text-indigo-600 group-hover:text-white transition-colors" />
            </div>
            <h2 className="text-2xl font-bold text-slate-900 mb-2">Reports History</h2>
            <p className="text-slate-500">View and manage your previous medical analysis reports.</p>
          </div>
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <ClockIcon className="h-32 w-32" />
          </div>
        </button>
      </div>

      <div>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-900">Recent Reports</h3>
          <button onClick={onViewHistory} className="text-blue-600 hover:text-blue-700 font-semibold text-sm">View all</button>
        </div>

        {latestReports.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center text-slate-400">
            No reports yet. Start your first analysis above.
          </div>
        ) : (
          <div className="grid gap-4">
            {latestReports.map(report => (
              <div 
                key={report.id} 
                className="bg-white p-4 rounded-xl border border-slate-200 flex items-center justify-between hover:bg-slate-50 cursor-pointer transition-colors"
                onClick={() => onViewReport(report)}
              >
                <div className="flex items-center space-x-4">
                  <div className="bg-blue-50 p-2.5 rounded-lg">
                    <ClipboardDocumentCheckIcon className="h-6 w-6 text-blue-600" />
                  </div>
                  <div>
                    <h4 className="font-semibold text-slate-900 line-clamp-1">{report.fileName}</h4>
                    <p className="text-xs text-slate-500">{new Date(report.timestamp).toLocaleDateString()}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                    report.analysis.confidence === 'high' ? 'bg-green-100 text-green-700' : 
                    report.analysis.confidence === 'medium' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                  }`}>
                    {report.analysis.confidence} confidence
                  </span>
                  <ChevronLeftIcon className="h-5 w-5 text-slate-300 rotate-180" />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
