};

const UploadView: React.FC<{ onBack: () => void; onFileSelect: (f: File) => void; isLoading: boolean; error: string | null }> = ({ onBack, onFileSelect, isLoading, error }) => {
  const [dragActive, setDragActive] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") setDragActive(true);
    else if (e.type === "dragleave") setDragActive(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelect(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-6">
        <div className="relative">
          <div className="w-24 h-24 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <ClipboardDocumentCheckIcon className="h-10 w-10 text-blue-600 opacity-20" />
          </div>
        </div>
        <div className="text-center">
          <h2 className="text-2xl font-bold text-slate-900">Analyzing Content...</h2>
          <p className="text-slate-500 mt-2">Our AI is processing your file with privacy-first protocols.</p>
        </div>
        <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-700 max-w-sm text-center">
          This usually takes 5-15 seconds depending on file complexity.
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto animate-fadeIn">
      <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-6 transition-colors">
        <ChevronLeftIcon className="h-5 w-5 mr-1" /> Back to Dashboard
      </button>

      <h2 className="text-3xl font-bold text-slate-900 mb-2">Upload Medical File</h2>
      <p className="text-slate-500 mb-8">Supported: JPG, PNG, DICOM, PDF, DOCX, TXT. Files are processed in memory and never stored on a server.</p>

      {error && (
        <div className="mb-6 p-4 bg-red-50 text-red-700 text-sm rounded-xl flex items-start space-x-2">
          <ExclamationTriangleIcon className="h-5 w-5 mt-0.5 shrink-0" />
          <span>{error}</span>
        </div>
      )}

      <div 
        onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop}
        className={`relative border-2 border-dashed rounded-3xl p-16 flex flex-col items-center justify-center transition-all ${
          dragActive ? 'border-blue-500 bg-blue-50/50' : 'border-slate-200 bg-white'
        }`}
      >
        <div className="bg-slate-50 p-6 rounded-2xl mb-4 group-hover:scale-110 transition-transform">
          <ArrowUpTrayIcon className="h-12 w-12 text-slate-400" />
        </div>
        <p className="text-lg font-semibold text-slate-900">Drag and drop file here</p>
        <p className="text-slate-400 mt-1 mb-6 text-sm text-center px-4">Maximum file size: 20MB. Encrypted locally before processing.</p>

        <label className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl cursor-pointer transition-all shadow-lg shadow-blue-200">
          Browse Files
          <input type="file" className="hidden" onChange={handleChange} accept="image/*,.pdf,.docx,.txt,.dicom" />
        </label>
      </div>

      <div className="mt-8 grid grid-cols-1 sm:grid-cols-3 gap-4 text-center">
        <div className="p-4 bg-slate-100/50 rounded-2xl">
          <div className="text-lg font-bold text-slate-700">100% Private</div>
          <div className="text-xs text-slate-500">On-device storage</div>
        </div>
        <div className="p-4 bg-slate-100/50 rounded-2xl">
          <div className="text-lg font-bold text-slate-700">Stateless AI</div>
          <div className="text-xs text-slate-500">Gemini Powered</div>
        </div>
        <div className="p-4 bg-slate-100/50 rounded-2xl">
          <div className="text-lg font-bold text-slate-700">Encrypted</div>
          <div className="text-xs text-slate-500">In-memory processing</div>
        </div>
      </div>
    </div>
  );
};

const ReportsListView: React.FC<{ reports: MedicalReport[]; onBack: () => void; onViewReport: (r: MedicalReport) => void; onDelete: (id: string) => void }> = ({ reports, onBack, onViewReport, onDelete }) => {
  return (
    <div className="animate-fadeIn">
      <div className="flex justify-between items-center mb-8">
        <div>
          <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-2 transition-colors">
            <ChevronLeftIcon className="h-4 w-4 mr-1" /> Dashboard
          </button>
          <h2 className="text-3xl font-bold text-slate-900">Analysis History</h2>
        </div>
        <span className="bg-slate-200 text-slate-600 px-3 py-1 rounded-full text-xs font-bold">{reports.length} Reports</span>
      </div>

