const UploadView: React.FC<{ onBack: () => void; onSubmit: (f: File, c: string) => void; isLoading: boolean; error: string | null }> = ({ onBack, onSubmit, isLoading, error }) => {
  const [dragActive, setDragActive] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [contextText, setContextText] = useState("");

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") setDragActive(true);
    else if (e.type === "dragleave") setDragActive(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setSelectedFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  const handleClearFile = () => {
    setSelectedFile(null);
  };

  const handleAnalyze = () => {
    if (selectedFile) {
      onSubmit(selectedFile, contextText);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-6">
        <div className="relative">
          <div className="w-24 h-24 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <DocumentMagnifyingGlassIcon className="h-10 w-10 text-blue-600 opacity-20" />
          </div>
        </div>
        <div className="text-center">
          <h2 className="text-2xl font-bold text-slate-900">Conducting Detailed Analysis...</h2>
          <p className="text-slate-500 mt-2">Gemini AI is examining your file and context in depth.</p>
        </div>
        <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-700 max-w-sm text-center">
          Detailed medical scans may take up to 20 seconds to process thoroughly.
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto animate-fadeIn no-print">
      <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-6 transition-colors">
        <ChevronLeftIcon className="h-5 w-5 mr-1" /> Back to Dashboard
      </button>

      <h2 className="text-3xl font-bold text-slate-900 mb-2">Upload & Contextualize</h2>
      <p className="text-slate-500 mb-8">Provide a medical file and optional context for a tailored, high-detail AI review.</p>

      {error && (
        <div className="mb-6 p-4 bg-red-50 text-red-700 text-sm rounded-xl flex items-start space-x-2">
          <ExclamationTriangleIcon className="h-5 w-5 mt-0.5 shrink-0" />
          <span>{error}</span>
        </div>
      )}

      {!selectedFile ? (
        <div 
          onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop}
          className={`relative border-2 border-dashed rounded-3xl p-16 flex flex-col items-center justify-center transition-all ${
            dragActive ? 'border-blue-500 bg-blue-50/50' : 'border-slate-200 bg-white'
          }`}
        >
          <div className="bg-slate-50 p-6 rounded-2xl mb-4">
            <ArrowUpTrayIcon className="h-12 w-12 text-slate-400" />
          </div>
          <p className="text-lg font-semibold text-slate-900">Drag and drop file here</p>
          <p className="text-slate-400 mt-1 mb-6 text-sm text-center px-4">X-rays, MRIs, PDFs, or Text documents up to 20MB.</p>

          <label className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl cursor-pointer transition-all shadow-lg shadow-blue-200">
            Browse Files
            <input type="file" className="hidden" onChange={handleChange} accept="image/*,.pdf,.docx,.txt,.dicom" />
