                <p className="text-sm font-bold text-slate-900">{selectedFile.name}</p>
                <p className="text-xs text-slate-400">{(selectedFile.size / 1024 / 1024).toFixed(2)} MB • {selectedFile.type || 'Medical Document'}</p>
              </div>
            </div>
            <button onClick={handleClearFile} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
              <XMarkIcon className="h-6 w-6" />
