import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "./types";

const SYSTEM_PROMPT = `You are an expert medical analysis AI with deep clinical knowledge. 
Your task is to provide an EXTREMELY DETAILED, comprehensive, and thorough analysis of the provided medical data (images or documents). 
Do not provide brief or generic responses. For each finding, explain its potential significance and context.

CRITICAL INSTRUCTIONS:
1. SERIOUSNESS: Categorize the findings as 'routine', 'moderate', 'urgent', or 'critical'. Provide a clear clinical reasoning for this categorization.
2. READINGS: Extract every single numerical value, measurement, or statistic mentioned or visible (e.g., blood pressure, heart rate, tumor dimensions, bone density scores, lab results).
3. Address any specific questions or context provided by the user with priority.
STRICTLY ADHERE TO THE JSON FORMAT.
DISCLAIMER: This is not a medical diagnosis. Users must consult a healthcare professional.`;

export async function analyzeMedicalFile(
  file: File,
  base64Data: string,
  userContext?: string
): Promise<AnalysisResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isImage = file.type.startsWith('image/') || file.name.toLowerCase().endsWith('.dicom');

  const analysisPrompt = `
    Perform a comprehensive and highly detailed analysis of this medical ${isImage ? 'image' : 'document'}. 

    ${userContext ? `The user has provided the following specific context or questions to address: "${userContext}"` : ""}

    Please provide:
    1. An exhaustive summary of the findings.
    2. A detailed list of any visible anomalies, faults, or concerning patterns.
    3. A detailed list of positive findings or normal indicators.
    4. Practical, detailed temporary guidance or next steps to discuss with a doctor.
    5. A confidence rating for this AI-generated assessment.
    6. A specific seriousness level (routine, moderate, urgent, or critical) with reasoning.
    7. A table of any numerical readings, statistics, or measurements found.
  `;

  const contents = {
    parts: [
      {
        inlineData: {
          mimeType: isImage ? 'image/png' : 'application/pdf',
          data: base64Data
        }
      },
      {
        text: analysisPrompt
      }
    ]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING, description: "A multi-paragraph, detailed summary of the clinical findings." },
          faults: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Specific technical details of any abnormalities found." },
          goods: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Specific technical details of normal/healthy findings." },
          temporary_guidance: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Detailed suggested questions for a doctor or next steps." },
          confidence: { type: Type.STRING, description: "low, medium, or high" },
          seriousness: { type: Type.STRING, description: "routine, moderate, urgent, or critical" },
          seriousness_explanation: { type: Type.STRING, description: "Why this seriousness level was chosen based on findings." },
          readings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING, description: "Name of the metric (e.g. Heart Rate)" },
                value: { type: Type.STRING, description: "The numerical value" },
                unit: { type: Type.STRING, description: "The measurement unit if available" },
                status: { type: Type.STRING, description: "normal, abnormal, or borderline" }
              },
              required: ["label", "value", "status"]
            }
          },
          disclaimer: { type: Type.STRING }
        },
        required: ["summary", "faults", "goods", "temporary_guidance", "confidence", "seriousness", "seriousness_explanation", "readings", "disclaimer"]
      }
    }
  });

  const text = response.text || "{}";
  try {
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Analysis failed to generate a valid report. Please ensure the file is clear and try again.");
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, User, MedicalReport, AnalysisResult, Reading } from './types';
import { authStorage, db, hashPassword } from './storage';
import { analyzeMedicalFile } from './geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowUpTrayIcon, 
  ClockIcon, 
  ArrowLeftOnRectangleIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  XCircleIcon,
  TrashIcon,
  ChevronLeftIcon,
  InformationCircleIcon,
  DocumentMagnifyingGlassIcon,
  XMarkIcon,
  ArrowDownTrayIcon,
  ChartBarIcon,
  ShieldAlertIcon,
  ShieldCheckIcon
} from '@heroicons/react/24/outline';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

export default function App() {
  const [currentPage, setCurrentPage] = useState<Page>(Page.LOGIN);
  const [currentUser, setCurrentUser] = useState<string | null>(authStorage.getSession());
  const [reports, setReports] = useState<MedicalReport[]>([]);
  const [activeReport, setActiveReport] = useState<MedicalReport | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth Handling
  const handleLogin = async (username: string, pass: string) => {
    const users = authStorage.getUsers();
    const hash = await hashPassword(pass);
    const existing = users.find(u => u.username === username);

    if (existing) {
      if (existing.passwordHash === hash) {
        completeLogin(username);
      } else {
        setError('Invalid credentials');
      }
    } else {
      // Auto-register for this demo
      const newUser = { username, passwordHash: hash };
      authStorage.saveUser(newUser);
      completeLogin(username);
    }
  };

  const completeLogin = (username: string) => {
    setCurrentUser(username);
    authStorage.setSession(username);
    setError(null);
    setCurrentPage(Page.DASHBOARD);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    authStorage.setSession(null);
    setCurrentPage(Page.LOGIN);
  };

  // Data Loading
  useEffect(() => {
    if (currentUser) {
      db.getReports(currentUser).then(setReports);
    }
  }, [currentUser, currentPage]);

  const onFileUpload = async (file: File, context: string) => {
    if (!currentUser) return;
    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const res = reader.result as string;
          resolve(res.split(',')[1]);
        };
        reader.readAsDataURL(file);
      });

      const base64 = await base64Promise;
      const result = await analyzeMedicalFile(file, base64, context);

      const newReport: MedicalReport = {
        id: Math.random().toString(36).substr(2, 9),
        userId: currentUser,
        timestamp: Date.now(),
        fileName: file.name,
        fileType: file.type,
        analysis: result
      };

      await db.saveReport(newReport);
      setActiveReport(newReport);
      setCurrentPage(Page.RESULT);
    } catch (err: any) {
      setError(err.message || "Failed to analyze file");
    } finally {
      setIsLoading(false);
    }
  };

  const deleteReport = async (id: string) => {
    await db.deleteReport(id);
    const updated = reports.filter(r => r.id !== id);
    setReports(updated);
  };

  // Rendering logic
  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} error={error} setError={setError} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setCurrentPage(Page.DASHBOARD)}>
              <ClipboardDocumentCheckIcon className="h-8 w-8 text-blue-600" />
              <span className="text-xl font-bold text-slate-900 tracking-tight">Medivise <span className="text-blue-600">AI</span></span>
            </div>
            <div className="flex items-center space-x-4">
              <span className="hidden sm:block text-sm text-slate-500 font-medium">Hello, {currentUser}</span>
              <button 
                onClick={handleLogout}
                className="p-2 text-slate-400 hover:text-red-600 transition-colors"
                title="Logout"
              >
                <ArrowLeftOnRectangleIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow max-w-5xl w-full mx-auto p-4 sm:p-6 lg:p-8">
        {currentPage === Page.DASHBOARD && (
          <DashboardView 
            onUpload={() => setCurrentPage(Page.UPLOAD)} 
            onViewHistory={() => setCurrentPage(Page.REPORTS)}
            latestReports={reports.slice(0, 3)}
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
          />
        )}
        {currentPage === Page.UPLOAD && (
          <UploadView 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onSubmit={onFileUpload} 
            isLoading={isLoading} 
            error={error}
          />
        )}
        {currentPage === Page.REPORTS && (
          <ReportsListView 
            reports={reports} 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
            onDelete={deleteReport}
          />
        )}
        {currentPage === Page.RESULT && activeReport && (
          <ResultView 
            report={activeReport} 
            onBack={() => setCurrentPage(Page.REPORTS)} 
          />
        )}
      </main>

      {/* Persistent Disclaimer */}
      <footer className="bg-slate-100 border-t border-slate-200 py-4 px-6 text-center text-xs text-slate-500 no-print">
        <p className="max-w-3xl mx-auto">
          <strong>MEDICAL DISCLAIMER:</strong> This tool is for educational purposes only. It uses AI to identify patterns and does not provide professional medical advice, diagnosis, or treatment. Always seek the advice of your physician or other qualified health provider with any questions you may have regarding a medical condition.
        </p>
      </footer>
    </div>
  );
}

