const ResultView: React.FC<{ report: MedicalReport; onBack: () => void }> = ({ report, onBack }) => {
  const a = report.analysis;
  const [isExporting, setIsExporting] = useState(false);
  const reportRef = useRef<HTMLDivElement>(null);

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);

    try {
      const element = reportRef.current;

      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#f8fafc',
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF({
        orientation: 'p',
        unit: 'mm',
        format: 'a4',
      });

      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

      const pageHeight = pdf.internal.pageSize.getHeight();
      let heightLeft = pdfHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, pdfHeight);
      heightLeft -= pageHeight;

      while (heightLeft >= 0) {
        position = heightLeft - pdfHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, pdfHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`Medivise_Report_${report.fileName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.pdf`);
    } catch (err) {
      console.error("PDF generation failed:", err);
      alert("Failed to generate PDF. You can also try using the browser's Print feature.");
    } finally {
      setIsExporting(false);
    }
  };

  const getSeriousnessColor = (level: string) => {
    switch (level) {
      case 'critical': return 'bg-red-600 text-white border-red-700 shadow-red-200';
      case 'urgent': return 'bg-orange-500 text-white border-orange-600 shadow-orange-100';
      case 'moderate': return 'bg-amber-400 text-slate-900 border-amber-500 shadow-amber-50';
      default: return 'bg-green-500 text-white border-green-600 shadow-green-100';
    }
  };

  const getSeriousnessIcon = (level: string) => {
    if (level === 'critical' || level === 'urgent') return <ShieldExclamationIcon className="h-8 w-8" />;
    return <ShieldCheckIcon className="h-8 w-8" />;
  };

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn pb-12">
      <div className="flex justify-between items-start mb-8 no-print">
        <div>
          <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-2 transition-colors">
            <ChevronLeftIcon className="h-4 w-4 mr-1" /> History
          </button>
          <h2 className="text-3xl font-bold text-slate-900">Analysis Result</h2>
          <p className="text-slate-500 mt-1">Generated for: {report.fileName}</p>
        </div>
        <div className="text-right">
          <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest ${
            a.confidence === 'high' ? 'bg-green-100 text-green-700 border border-green-200' : 
            a.confidence === 'medium' ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-red-100 text-red-700 border border-red-200'
          }`}>
            {a.confidence} Confidence
          </span>
          <p className="text-[10px] text-slate-400 mt-1">{new Date(report.timestamp).toLocaleString()}</p>
        </div>
      </div>

      <div ref={reportRef} className="grid grid-cols-1 gap-6 p-1 sm:p-2">

        {/* Print-only Header */}
        <div className="hidden print-only bg-white p-8 border-b-2 border-slate-100 mb-6 rounded-3xl">
          <div className="flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <ClipboardDocumentCheckIcon className="h-10 w-10 text-blue-600" />
              <h1 className="text-3xl font-black text-slate-900 tracking-tight">Medivise <span className="text-blue-600">AI</span></h1>
            </div>
            <div className="text-right">
              <h2 className="text-lg font-bold text-slate-900">Clinical Analysis Report</h2>
              <p className="text-sm text-slate-500">Report ID: {report.id}</p>
            </div>
          </div>
          <div className="mt-6 grid grid-cols-2 gap-4 pt-6 border-t border-slate-50">
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Subject Reference</p>
              <p className="text-sm font-semibold text-slate-800">{report.fileName}</p>
            </div>
            <div className="text-right">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Analysis Timestamp</p>
              <p className="text-sm font-semibold text-slate-800">{new Date(report.timestamp).toLocaleString()}</p>
            </div>
