import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "./types";

const SYSTEM_PROMPT = `You are an expert specialist physician and diagnostic radiologist with deep clinical knowledge. 
Your task is to provide an EXTREMELY DETAILED, professional, and clinical-grade analysis of the provided medical data. 

CRITICAL INSTRUCTIONS:
1. CLINICAL IMPRESSION / DIAGNOSIS: Provide a structured "Differential Diagnosis" or "Clinical Impression". This must be highly detailed, discussing the most likely clinical pathologies, potential secondary causes, and the pathognomonic evidence supporting these conclusions.
2. SERIOUSNESS: Categorize the findings as 'routine', 'moderate', 'urgent', or 'critical'. Provide a clear clinical reasoning for this categorization based on mortality/morbidity risks.
3. READINGS: Extract every single numerical value, measurement, or statistic (e.g., bone age, ejection fraction, Hounsfield units, dimensions in mm/cm, lab markers).
4. Address any specific questions or context provided by the user with highest priority.

STRICTLY ADHERE TO THE JSON FORMAT.
DISCLAIMER: This is an AI-generated clinical impression for professional reference. It does not constitute a legally binding medical diagnosis. Users must consult a licensed medical doctor.`;

export async function analyzeMedicalFile(
  file: File,
  base64Data: string,
  userContext?: string
): Promise<AnalysisResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isImage = file.type.startsWith('image/') || file.name.toLowerCase().endsWith('.dicom');

  const analysisPrompt = `
    Perform a comprehensive, clinical-grade analysis of this medical ${isImage ? 'image' : 'document'}. 

    ${userContext ? `User context/concerns: "${userContext}"` : ""}

    Please provide:
    1. An exhaustive summary of findings.
    2. A structured "Differential Diagnosis / Clinical Impression" section detailing the most likely medical conditions identified.
    3. Technical details of all visible anomalies or faults.
    4. Details of all normal indicators.
    5. Clinical guidance and evidence-based next steps.
    6. Confidence rating.
    7. Urgency/Seriousness level with specific clinical reasoning.
    8. Table of numerical readings/statistics.
  `;

  const contents = {
    parts: [
      {
        inlineData: {
          mimeType: isImage ? 'image/png' : 'application/pdf',
          data: base64Data
        }
      },
      {
        text: analysisPrompt
      }
    ]
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING, description: "Detailed clinical summary of the report." },
          diagnosis: { type: Type.STRING, description: "Comprehensive Differential Diagnosis / Clinical Impression section." },
          faults: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Specific abnormalities found." },
          goods: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Specific normal findings." },
          temporary_guidance: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Recommended clinical next steps." },
          confidence: { type: Type.STRING, description: "low, medium, or high" },
          seriousness: { type: Type.STRING, description: "routine, moderate, urgent, or critical" },
          seriousness_explanation: { type: Type.STRING, description: "Clinical reasoning for urgency level." },
          readings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                value: { type: Type.STRING },
                unit: { type: Type.STRING },
                status: { type: Type.STRING }
              },
              required: ["label", "value", "status"]
            }
          },
          disclaimer: { type: Type.STRING }
        },
        required: ["summary", "diagnosis", "faults", "goods", "temporary_guidance", "confidence", "seriousness", "seriousness_explanation", "readings", "disclaimer"]
      }
    }
  });

  const text = response.text || "{}";
  try {
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Analysis failed. Please ensure the file contains clear medical data and try again.");
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Page, User, MedicalReport, AnalysisResult, Reading } from './types';
import { authStorage, db, hashPassword } from './storage';
import { analyzeMedicalFile } from './geminiService';
import { 
  ClipboardDocumentCheckIcon, 
  ArrowUpTrayIcon, 
  ClockIcon, 
  ArrowLeftOnRectangleIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  XCircleIcon,
  TrashIcon,
  ChevronLeftIcon,
  InformationCircleIcon,
  DocumentMagnifyingGlassIcon,
  XMarkIcon,
  ArrowDownTrayIcon,
  ChartBarIcon,
  ShieldExclamationIcon,
  ShieldCheckIcon,
  BeakerIcon
} from '@heroicons/react/24/outline';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

export default function App() {
  const [currentPage, setCurrentPage] = useState<Page>(Page.LOGIN);
  const [currentUser, setCurrentUser] = useState<string | null>(authStorage.getSession());
  const [reports, setReports] = useState<MedicalReport[]>([]);
  const [activeReport, setActiveReport] = useState<MedicalReport | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Auth Handling
  const handleLogin = async (username: string, pass: string) => {
    const users = authStorage.getUsers();
    const hash = await hashPassword(pass);
    const existing = users.find(u => u.username === username);

    if (existing) {
      if (existing.passwordHash === hash) {
        completeLogin(username);
      } else {
        setError('Invalid credentials');
      }
    } else {
      const newUser = { username, passwordHash: hash };
      authStorage.saveUser(newUser);
      completeLogin(username);
    }
  };

  const completeLogin = (username: string) => {
    setCurrentUser(username);
    authStorage.setSession(username);
    setError(null);
    setCurrentPage(Page.DASHBOARD);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    authStorage.setSession(null);
    setCurrentPage(Page.LOGIN);
  };

  useEffect(() => {
    if (currentUser) {
      db.getReports(currentUser).then(setReports);
    }
  }, [currentUser, currentPage]);

  const onFileUpload = async (file: File, context: string) => {
    if (!currentUser) return;
    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const res = reader.result as string;
          resolve(res.split(',')[1]);
        };
        reader.readAsDataURL(file);
      });

      const base64 = await base64Promise;
      const result = await analyzeMedicalFile(file, base64, context);

      const newReport: MedicalReport = {
        id: Math.random().toString(36).substr(2, 9),
        userId: currentUser,
        timestamp: Date.now(),
        fileName: file.name,
        fileType: file.type,
        analysis: result
      };

      await db.saveReport(newReport);
      setActiveReport(newReport);
      setCurrentPage(Page.RESULT);
    } catch (err: any) {
      setError(err.message || "Failed to analyze file");
    } finally {
      setIsLoading(false);
    }
  };

  const deleteReport = async (id: string) => {
    await db.deleteReport(id);
    const updated = reports.filter(r => r.id !== id);
    setReports(updated);
  };

  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} error={error} setError={setError} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-10 no-print">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setCurrentPage(Page.DASHBOARD)}>
              <ClipboardDocumentCheckIcon className="h-8 w-8 text-blue-600" />
              <span className="text-xl font-bold text-slate-900 tracking-tight">Medivise <span className="text-blue-600">AI</span></span>
            </div>
            <div className="flex items-center space-x-4">
              <span className="hidden sm:block text-sm text-slate-500 font-medium">Hello, {currentUser}</span>
              <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="Logout">
                <ArrowLeftOnRectangleIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow max-w-5xl w-full mx-auto p-4 sm:p-6 lg:p-8">
        {currentPage === Page.DASHBOARD && (
          <DashboardView 
            onUpload={() => setCurrentPage(Page.UPLOAD)} 
            onViewHistory={() => setCurrentPage(Page.REPORTS)}
            latestReports={reports.slice(0, 3)}
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
          />
        )}
        {currentPage === Page.UPLOAD && (
          <UploadView 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onSubmit={onFileUpload} 
            isLoading={isLoading} 
            error={error}
          />
        )}
        {currentPage === Page.REPORTS && (
          <ReportsListView 
            reports={reports} 
            onBack={() => setCurrentPage(Page.DASHBOARD)} 
            onViewReport={(r) => { setActiveReport(r); setCurrentPage(Page.RESULT); }}
            onDelete={deleteReport}
          />
        )}
        {currentPage === Page.RESULT && activeReport && (
          <ResultView 
            report={activeReport} 
            onBack={() => setCurrentPage(Page.REPORTS)} 
          />
        )}
      </main>

      <footer className="bg-slate-100 border-t border-slate-200 py-4 px-6 text-center text-xs text-slate-500 no-print">
        <p className="max-w-3xl mx-auto">
          <strong>MEDICAL DISCLAIMER:</strong> This tool is for educational purposes only. It uses AI to identify patterns and does not provide professional medical advice, diagnosis, or treatment. Always seek the advice of your physician or other qualified health provider with any questions you may have regarding a medical condition.
        </p>
      </footer>
    </div>
  );
}

