const UploadView: React.FC<{ onBack: () => void; onSubmit: (f: File, c: string) => void; isLoading: boolean; error: string | null }> = ({ onBack, onSubmit, isLoading, error }) => {
  const [dragActive, setDragActive] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [contextText, setContextText] = useState("");

  const handleDrag = (e: React.DragEvent) => { e.preventDefault(); e.stopPropagation(); setDragActive(e.type === "dragenter" || e.type === "dragover"); };
  const handleDrop = (e: React.DragEvent) => { e.preventDefault(); e.stopPropagation(); setDragActive(false); if (e.dataTransfer.files?.[0]) setSelectedFile(e.dataTransfer.files[0]); };
  const handleAnalyze = () => { if (selectedFile) onSubmit(selectedFile, contextText); };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-6">
        <div className="w-24 h-24 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
        <div className="text-center">
          <h2 className="text-2xl font-bold text-slate-900">Processing Medical Data...</h2>
          <p className="text-slate-500 mt-2">Gemini AI is generating a detailed Clinical Impression.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto animate-fadeIn no-print">
      <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-6 transition-colors">
        <ChevronLeftIcon className="h-5 w-5 mr-1" /> Back
      </button>
      <h2 className="text-3xl font-bold text-slate-900 mb-2">Generate Clinical Impression</h2>
      <p className="text-slate-500 mb-8">Upload a scan or document for high-fidelity AI diagnostics.</p>
      {error && <div className="mb-6 p-4 bg-red-50 text-red-700 text-sm rounded-xl flex items-center space-x-2"><ExclamationTriangleIcon className="h-5 w-5" /><span>{error}</span></div>}
      {!selectedFile ? (
        <div onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop} className={`border-2 border-dashed rounded-3xl p-16 flex flex-col items-center justify-center transition-all ${dragActive ? 'border-blue-500 bg-blue-50/50' : 'border-slate-200 bg-white'}`}>
          <ArrowUpTrayIcon className="h-12 w-12 text-slate-400 mb-4" />
          <p className="text-lg font-semibold text-slate-900 mb-4">Drop medical file here</p>
          <label className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl cursor-pointer transition-all">
            Browse Files <input type="file" className="hidden" onChange={(e) => e.target.files?.[0] && setSelectedFile(e.target.files[0])} />
          </label>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="bg-white border border-slate-200 rounded-2xl p-6 flex items-center justify-between shadow-sm">
            <div className="flex items-center space-x-4">
              <DocumentMagnifyingGlassIcon className="h-8 w-8 text-blue-600" />
              <div><p className="text-sm font-bold text-slate-900">{selectedFile.name}</p></div>
            </div>
            <button onClick={() => setSelectedFile(null)} className="text-slate-400 hover:text-red-500 transition-colors"><XMarkIcon className="h-6 w-6" /></button>
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-bold text-slate-700">Clinical Context (Optional)</label>
            <textarea className="w-full min-h-[120px] p-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="Symptoms, duration, medical history..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
          </div>
          <button onClick={handleAnalyze} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-xl transition-all">Generate Detailed Analysis</button>
        </div>
      )}
    </div>
  );
};

const ReportsListView: React.FC<{ reports: MedicalReport[]; onBack: () => void; onViewReport: (r: MedicalReport) => void; onDelete: (id: string) => void }> = ({ reports, onBack, onViewReport, onDelete }) => {
  return (
    <div className="animate-fadeIn no-print">
      <div className="flex justify-between items-center mb-8">
        <div><button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-2"><ChevronLeftIcon className="h-4 w-4 mr-1" /> Dashboard</button>
        <h2 className="text-3xl font-bold text-slate-900">Analysis History</h2></div>
      </div>
      {reports.length === 0 ? (
        <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-20 text-center text-slate-400">No history found.</div>
      ) : (
        <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs font-bold border-b border-slate-200">
              <tr><th className="px-6 py-4">Report</th><th className="px-6 py-4">Date</th><th className="px-6 py-4">Urgency</th><th className="px-6 py-4 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {reports.map(report => (
                <tr key={report.id} className="hover:bg-slate-50/50 group">
                  <td className="px-6 py-5 cursor-pointer font-semibold text-slate-900" onClick={() => onViewReport(report)}>{report.fileName}</td>
                  <td className="px-6 py-5 text-sm text-slate-500">{new Date(report.timestamp).toLocaleDateString()}</td>
                  <td className="px-6 py-5"><span className="px-2 py-1 rounded text-[10px] font-bold uppercase bg-slate-100 text-slate-600">{report.analysis.seriousness}</span></td>
                  <td className="px-6 py-5 text-right"><button onClick={() => onDelete(report.id)} className="p-2 text-slate-400 hover:text-red-600"><TrashIcon className="h-5 w-5" /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

const ResultView: React.FC<{ report: MedicalReport; onBack: () => void }> = ({ report, onBack }) => {
  const a = report.analysis;
  const [isExporting, setIsExporting] = useState(false);
  const reportRef = useRef<HTMLDivElement>(null);

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    setIsExporting(true);
    try {
      const element = reportRef.current;
      const canvas = await html2canvas(element, { scale: 2, useCORS: true, backgroundColor: '#f8fafc' });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Medivise_Diagnostic_${report.fileName.replace(/[^a-z0-9]/gi, '_')}.pdf`);
    } catch (err) { alert("PDF generation failed."); } finally { setIsExporting(false); }
  };

  const getUrgencyColor = (level: string) => {
    switch (level) {
      case 'critical': return 'bg-red-600 text-white border-red-700';
      case 'urgent': return 'bg-orange-500 text-white border-orange-600';
      case 'moderate': return 'bg-amber-400 text-slate-900 border-amber-500';
      default: return 'bg-emerald-500 text-white border-emerald-600';
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn pb-12">
      <div className="flex justify-between items-start mb-8 no-print">
        <div><button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 mb-2 transition-colors"><ChevronLeftIcon className="h-4 w-4 mr-1" /> History</button>
        <h2 className="text-3xl font-bold text-slate-900">Clinical Impression</h2></div>
        <div className="text-right">
          <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-xs font-bold uppercase">{a.confidence} Confidence</span>
          <p className="text-[10px] text-slate-400 mt-1">{new Date(report.timestamp).toLocaleString()}</p>
        </div>
      </div>

      <div ref={reportRef} className="space-y-6">
        {/* Urgency Section */}
        <div className={`p-8 rounded-3xl border-2 shadow-xl flex flex-col md:flex-row items-center md:items-start space-y-4 md:space-y-0 md:space-x-6 ${getUrgencyColor(a.seriousness)}`}>
          <div className="shrink-0 p-3 bg-white/20 rounded-2xl"><ShieldExclamationIcon className="h-8 w-8" /></div>
          <div>
            <h3 className="text-sm font-black uppercase tracking-widest opacity-80 mb-1">Clinical Urgency: {a.seriousness}</h3>
            <p className="text-2xl font-bold mb-2">{a.seriousness_explanation}</p>
          </div>
        </div>

        {/* DIAGNOSIS / CLINICAL IMPRESSION - MAIN SECTION */}
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <div className="flex items-center space-x-3 mb-6">
            <BeakerIcon className="h-6 w-6 text-blue-600" />
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Clinical Impression & Differential Diagnosis</h3>
          </div>
          <div className="bg-slate-50/50 p-6 rounded-2xl border border-slate-100 border-l-4 border-l-blue-600">
            <p className="text-xl text-slate-800 leading-relaxed font-semibold whitespace-pre-wrap">{a.diagnosis}</p>
          </div>
        </div>

        {/* Extracted Data Section */}
        {a.readings && a.readings.length > 0 && (
          <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
            <div className="flex items-center space-x-3 mb-6"><ChartBarIcon className="h-6 w-6 text-indigo-600" /><h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Extracted Clinical Data</h3></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {a.readings.map((r, i) => (
                <div key={i} className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <p className="text-xs font-bold text-slate-400 uppercase mb-1">{r.label}</p>
                  <p className="text-lg font-black text-slate-900">{r.value} <span className="text-xs font-medium text-slate-500">{r.unit}</span></p>
                  <span className={`text-[10px] font-bold uppercase mt-2 inline-block ${r.status === 'abnormal' ? 'text-red-500' : r.status === 'borderline' ? 'text-amber-500' : 'text-green-500'}`}>{r.status}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Detailed Summary */}
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Detailed Clinical Narrative</h3>
          <p className="text-slate-700 leading-relaxed whitespace-pre-wrap">{a.summary}</p>
        </div>

        {/* Key Findings Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-red-50/30 p-6 rounded-3xl border border-red-100">
            <h4 className="text-sm font-bold text-red-800 uppercase tracking-widest mb-4 flex items-center"><XCircleIcon className="h-5 w-5 mr-2" /> Key Abnormalities</h4>
            <ul className="space-y-2">{a.faults.map((f, i) => <li key={i} className="bg-white p-3 rounded-xl border border-red-50 text-sm text-slate-700 shadow-sm">{f}</li>)}</ul>
          </div>
          <div className="bg-emerald-50/30 p-6 rounded-3xl border border-emerald-100">
            <h4 className="text-sm font-bold text-emerald-800 uppercase tracking-widest mb-4 flex items-center"><CheckCircleIcon className="h-5 w-5 mr-2" /> Unremarkable Findings</h4>
            <ul className="space-y-2">{a.goods.map((g, i) => <li key={i} className="bg-white p-3 rounded-xl border border-emerald-50 text-sm text-slate-700 shadow-sm">{g}</li>)}</ul>
          </div>
        </div>

        {/* Next Steps */}
        <div className="bg-blue-50/50 p-8 rounded-3xl border border-blue-100">
          <h3 className="text-sm font-bold text-blue-800 uppercase tracking-widest mb-6">Clinical Next Steps</h3>
          <div className="space-y-3">
            {a.temporary_guidance.map((g, i) => (
              <div key={i} className="bg-white p-4 rounded-xl border border-blue-100 flex items-start space-x-3 text-sm text-slate-700 font-medium shadow-sm">
                <InformationCircleIcon className="h-5 w-5 text-blue-500 mt-0.5 shrink-0" /><span>{g}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Print only footer */}
        <div className="bg-slate-900 p-8 rounded-3xl text-white">
          <h3 className="text-lg font-bold mb-2 flex items-center"><ExclamationTriangleIcon className="h-6 w-6 text-amber-400 mr-2" /> Professional Reference Notice</h3>
          <p className="text-sm text-slate-400 leading-relaxed mb-6">{a.disclaimer} Always correlate findings with clinical symptoms and physical examination by a specialist.</p>
          <div className="no-print"><button onClick={handleDownloadPDF} disabled={isExporting} className="bg-blue-600 hover:bg-blue-500 px-8 py-3 rounded-xl text-sm font-bold transition-all flex items-center space-x-2 disabled:opacity-50">
            {isExporting ? <span>Generating...</span> : <><ArrowDownTrayIcon className="h-5 w-5" /><span>Export Diagnostic PDF</span></>}
          </button></div>
        </div>
      </div>
    </div>
  );
};
